use customer
 
select *from customer_shopping_behavior;	
limit 20;

#Q1.What is the total revenue generated by male vs.female customers?
select gender,sum(purchase_amount)
from customer_shopping_behavior 
group by gender; 

#Q2.which customers used a discount but still spent more than the average purchase amount?
select customer_id,purchase_amount
from customer_shopping_behavior;	
where discount_applied="yes"and purchase_amount>(select avg(purchase_amount)
							  from customer_shopping_behavior)
#Q3.Which are the top 5 products with the highest average review rating?
select item_purchased,ROUND(avg(review_rating),2) as Average_review_rate
from customer_shopping_behavior
group by item_purchased 
order by avg(review_rating) desc 
limit 5;

#Q4. Compare the Average Purchase Amount between Standard and Express shipping  
select shipping_type,round(AVG(purchase_amount),2)
from customer_shopping_behavior
where shipping_type in("Standard","Express")
group by  shipping_type;

#Q5. Do subscribed customers spend more? Compare average spend and toatal revenue between subscribers and non_subscribers?
select subscription_status,
count(customer_id)as total_customers,
round(avg(purchase_amount),2) as avg_spend ,
SUM(purchase_amount) as total_revenue
from customer_shopping_behavior
group by subscription_status
order  by total_revenue,avg_spend desc;

#Q6.Which 5 products have the highest percentage of purchase with discounts applied?
select item_purchased,
round(100*sum(case when discount_applied='Yes' then 1 else 0 end)/count(*),2) as discount_rate 
from customer_shopping_behavior
group by  item_purchased
order by discount_rate desc 
limit 5;

#Q5. Segment customers into New,Returning,and Loyal based on their total number of 
     #previous purchase,and show the count of each segment.
with customer_type as(
select customer_id,previous_purchases,
case
      when previous_purchases=1 then "New" 
      when previous_purchases between 2 and 10 then "Returning"
      else " Loyal"
      end as customer_segnment
from customer_shopping_behavior
)
select customer_segnment,count(*)as "no_of_customers"
from customer_type
group by customer_segnment
   
#Q8.What are the top 3 most purchased products within each category?
with item_counts as(
select item_purchased,
        category,
        count(customer_id) as total_orders,
		row_number() over(partition by category order by count(customer_id)desc) as item_rank
        from customer_shopping_behavior
        group by category,item_purchased )
select item_rank, item_purchased,category, total_orders
from item_counts  
where item_rank<=3;

#Q9 Are customers who are repeat buyers (more than 5 previous purchases) also likely to subscribe?
select subscription_status,
       count(customer_id) as repeat_buyers
	    from customer_shopping_behavior
        where previous_purchases>5
		group by subscription_status

#Q10 What is the revenue contribution of each age?
select age_group ,sum(purchase_amount) as total_revenue
from customer_shopping_behavior
group by age_group
order by total_revenue desc;


    